#include <stdio.h>
#include <assert.h>
#include <math.h>
#include <stdlib.h>

/*
This program generates a table of structs that contains the first n precomputed scales
used to calculate the regression matrix. It is executed once before compilation to produce
a header file. This header file contains the values needed for the transform and the
required struct definition.
*/

typedef struct
{
    double A, B, C, D, E, F;
} MatInverse;

// these stay the same during function call
double XtX_00 = 1;
double XtX_02 = 0;
double XtX_11 = 0;
double XtX_12 = 0;
double XtX_13 = 0;
double XtX_22 = 0;

int prevScale = 0;

MatInverse inverseForScale(int scale)
{
    assert(scale - 1 == prevScale);

    XtX_00 += 2;
    XtX_02 += (double)(scale * scale);
    XtX_11 = XtX_02 * 2;
    XtX_13 += (double)(scale * scale * scale);
    XtX_12 = -XtX_13;
    XtX_22 += (double)(scale * scale * scale * scale);

    // decomposition matrix L, see https://en.wikipedia.org/wiki/Cholesky_decomposition
    double L_00 = sqrt(XtX_00);
    double L_11 = sqrt(XtX_11);
    double L_20 = XtX_02 / L_00;
    double L_21 = XtX_12 / L_11;
    double L_20sq = L_20 * L_20;
    double L_21sq = L_21 * L_21;
    double L_22 = sqrt(XtX_22 - L_20sq - L_21sq);
    double L_32 = 1 / L_22 * (-L_20sq + L_21sq);
    double L_33 = sqrt(XtX_22 - L_20sq - L_21sq - L_32 * L_32);

    // inverse of L
    double inv_00 = 1 / L_00;
    double inv_11 = 1 / L_11;
    double inv_22 = 1 / L_22;
    double inv_33 = 1 / L_33;
    double inv_20 = -L_20 * inv_00 / L_22;
    double inv_30 = -(L_20 * inv_00 + L_32 * inv_20) / L_33;
    double inv_21 = -L_21 * inv_11 / L_22;
    double inv_31 = -(-L_21 * inv_11 + L_32 * inv_21) / L_33;
    double inv_32 = -L_32 * inv_22 / L_33;

    MatInverse inv = {0, 0, 0, 0, 0, 0};
    inv.A = inv_00 * inv_00 + inv_20 * inv_20 + inv_30 * inv_30; // cell: 0,0
    inv.B = inv_22 * inv_20 + inv_32 * inv_30;                   // cell: 0,2
    inv.C = inv_11 * inv_11 + inv_21 * inv_21 + inv_31 * inv_31; // cell: 1,1
    inv.D = -inv_31 * inv_33;                                    // cell: 1,2
    inv.E = inv_33 * inv_33;                                     // cell: 2,2
    inv.F = inv_32 * inv_33;                                     // cell: 2,3

    return inv;
}

int main(int argc, char const *argv[]) // the only permitted argument is the highest pre-calculated scale
{
    assert(argc == 2);
    const int maxscale = atoi(argv[1]);

    // printf("%s\n%s\n", argv[0], argv[1]);

    int charCount = 0;

    const char comment[191] = "// This file was automatically generated by the program described in qalgorithms_matinverse.c\n"
                              "// Compile it using the command gcc -o ../build/precalc_mat.exe ./qalgorithms_matinverse.c -lm\n\n";
    charCount += 191;

    char maxscale_def[100];
    charCount += sprintf(maxscale_def, "#ifndef QALGORITHMS_MAXSCALE_PRECOMPILED \n"
                                       "#define QALGORITHMS_MAXSCALE_PRECOMPILED %d\n\n",
                         maxscale);

    const char struct_def[56] = "typedef struct {double A, B, C, D, E, F;} MatInverse;\n\n";
    charCount += 56;

    // close brace is in separate block, includes nonsensical scale = 0
    const char arrayDef[61] = "const MatInverse qalgo_matInverse[] = {\n{0, 0, 0, 0, 0, 0},\n";
    charCount += 61;

    // every line is a set number of chars: {fff,fff,fff,fff,fff,fff},\n
    // Important: last element may not have a comma! Insert close brace instead
    const int linelength = 1 + 6 * 18 + 5 + 5 + 1 + 1 + 1 + 20; // brace + 6 * 16-decimal float + minus + commas + brace + comma + \n + safety margain
    char line[linelength];
    char block[linelength * maxscale];
    int position = 0;

    // scale = 0 undefined, last line (== maxscale) treated separately
    // first scale has values > 10, but only one significant decimal, so it is handled separately
    char firstline[95] = "{1.0, -1.0, 3002399751580329.5, 3002399751580329.5, 3002399751580331.5, -3002399751580328.0},\n";
    charCount += 95;
    // still has to run this function due to iterative dependency on first result
    MatInverse dummy = inverseForScale(1);
    prevScale = 1;

    for (int scale = 2; scale < maxscale; scale++)
    {
        MatInverse inv = inverseForScale(scale);
        charCount += snprintf(line, linelength, "{%0.16f,%0.16f,%0.16f,%0.16f,%0.16f,%0.16f},\n",
                              inv.A, inv.B, inv.C, inv.D, inv.E, inv.F);

        position += sprintf(block + position, "%s", line);
        prevScale = scale;
    }

    // process last element
    MatInverse inv = inverseForScale(maxscale);
    charCount += sprintf(line, "{%0.16f,%0.16f,%0.16f,%0.16f,%0.16f,%0.16f}};", // no comma and second closing brace / semicolon
                         inv.A, inv.B, inv.C, inv.D, inv.E, inv.F);

    const char end[9] = "\n#endif\n";
    charCount += 9;

    char merge[charCount];
    sprintf(merge, "%s%s%s%s%s%s%s%s", comment, maxscale_def, struct_def, arrayDef, firstline, block, line, end);

    // paste all parts together and write to file
    FILE *f = fopen("./qalgorithms_matinverse.h", "w");
    fprintf(f, merge);
    fclose(f);

    return 0;
}
